extraMethods.continueWithAuth:
async continueWithAuth(params: NetworkContinueWithAuthParameters): Promise<void>
/** @deprecated Pass a NetworkContinueWithAuthParameters object instead — will be removed in a future major version. */
async continueWithAuth(requestId: NetworkRequest, username: string, password: string): Promise<void>
async continueWithAuth(
  paramsOrRequestId: NetworkContinueWithAuthParameters | NetworkRequest,
  username?: string,
  password?: string,
): Promise<void> {
  let params: NetworkContinueWithAuthParameters
  if (typeof paramsOrRequestId === 'string') {
    if (username === undefined || password === undefined) {
      throw new Error('username and password are required when calling continueWithAuth with a request id')
    }
    params = {
      request: paramsOrRequestId,
      action: 'provideCredentials',
      credentials: { type: 'password', username, password },
    } as NetworkContinueWithAuthParameters
  } else {
    params = paramsOrRequestId as NetworkContinueWithAuthParameters
  }
  const response = await this.bidi.send({
    method: 'network.continueWithAuth',
    params: params as unknown as Record<string, unknown>,
  }) as Record<string, unknown>
  if (response['type'] === 'error') {
    throw new Error(`${response['error']}: ${response['message']}`)
  }
}

